var imgs = document.querySelectorAll(".img");
window.addEventListener("scroll", function(){
  var rect = document.querySelector(".track").getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var idx = Math.min(Math.floor(p * imgs.length), imgs.length - 1);
  imgs.forEach(function(s, i){ s.classList.toggle("is-on", i === idx); });
}, { passive: true });

var rail = document.querySelector(".rail");
window.addEventListener("scroll", function(){
  var rect = document.querySelector(".track").getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  rail.style.transform = "translateX(" + (-p * 300) + "vw)";
}, { passive: true });

